50	/// Result of branding operation.
51	#[derive(Debug)]
52	pub struct vofr_BrandResult {
53	    /// Allocated brand
54	    pub brand: u32,
55	    /// Whether this was a new brand (vs reused)
56	    pub is_new: bool,
57	    /// Computed super-SHA
