198	// =============================================================================
199	// Internal Functions (zvofr_*)
200	// =============================================================================
201	
202	/// Collect a single kit's assets.
203	fn zvofr_collect_kit(
204	    source: &Path,
205	    staging: &Path,
206	    kit: &vofc_Kit,
207	) -> Result<(u32, u32), String> {
208	    let mut count = 0u32;
209	    let mut cmd_count = 0u32;
210	    let cipher = kit.cipher.prefix();
211	
212	    // Walk source directory
213	    let entries = zvofr_walk_dir(source)?;
214	
215	    for entry in entries {
216	        let rel_path = entry.strip_prefix(source)
217	            .map_err(|e| format!("Path strip failed: {}", e))?;
218	
219	        // Skip vov_veiled/ directory
220	        if zvofr_is_veiled_path(rel_path) {
221	            continue;
222	        }
223	
224	        // Determine destination
225	        let file_name = rel_path.file_name()
226	            .and_then(|n| n.to_str())
227	            .unwrap_or("");
228	
229	        let dest = if zvofr_is_command_file(file_name, cipher) {
230	            // Route commands to commands/ subdirectory
231	            cmd_count += 1;
232	            let commands_dir = staging.join("commands");
233	            fs::create_dir_all(&commands_dir)
234	                .map_err(|e| format!("Failed to create commands dir: {}", e))?;
235	            commands_dir.join(file_name)
236	        } else {
237	            // Default: preserve relative path
238	            staging.join(rel_path)
239	        };
240	
241	        // Create parent directories
242	        if let Some(parent) = dest.parent() {
243	            fs::create_dir_all(parent)
244	                .map_err(|e| format!("Failed to create dir {}: {}", parent.display(), e))?;
245	        }
246	
247	        // Copy file
248	        fs::copy(&entry, &dest)
249	            .map_err(|e| format!("Failed to copy {} to {}: {}", entry.display(), dest.display(), e))?;
250	
251	        count += 1;
252	    }
253	
254	    Ok((count, cmd_count))
255	}
