257	/// Collect Claude config assets for a single kit.
258	/// Scans .claude/commands/ and .claude/hooks/ at kit forge root for cipher-matched files.
259	/// Uses CWD as kit forge root (commands run from project root per launcher convention).
260	/// Returns (commands_collected, hooks_collected).
261	fn zvofr_collect_claude_assets(
262	    _kit_forge: &Path,
263	    staging: &Path,
264	    cipher: &str,
265	) -> Result<(u32, u32), String> {
266	    let mut commands_count = 0u32;
267	    let mut hooks_count = 0u32;
268	
269	    // Kit forge root is CWD (launcher cd's to project root before execution)
270	    let kit_forge_root = Path::new(".");
271	
272	    // Collect commands from .claude/commands/
273	    let commands_source = kit_forge_root.join(".claude").join("commands");
274	    if commands_source.exists() {
275	        let commands_dest = staging.join("claude").join("commands");
276	        fs::create_dir_all(&commands_dest)
277	            .map_err(|e| format!("Failed to create claude/commands dir: {}", e))?;
278	
279	        commands_count = zvofr_copy_matching_files(&commands_source, &commands_dest, cipher, true)?;
280	    }
281	
282	    // Collect hooks from .claude/hooks/
283	    let hooks_source = kit_forge_root.join(".claude").join("hooks");
284	    if hooks_source.exists() {
285	        let hooks_dest = staging.join("claude").join("hooks");
286	        fs::create_dir_all(&hooks_dest)
287	            .map_err(|e| format!("Failed to create claude/hooks dir: {}", e))?;
288	
289	        hooks_count = zvofr_copy_matching_files(&hooks_source, &hooks_dest, cipher, false)?;
290	    }
291	
292	    Ok((commands_count, hooks_count))
293	}
294	
295	/// Copy files matching cipher pattern from source to dest.
296	/// is_command determines whether to match commands (c-) or hooks (h-).
297	/// Returns count of files copied.
298	fn zvofr_copy_matching_files(
299	    source_dir: &Path,
300	    dest_dir: &Path,
301	    cipher: &str,
302	    is_command: bool,
303	) -> Result<u32, String> {
304	    let mut count = 0u32;
305	
306	    let entries = fs::read_dir(source_dir)
307	        .map_err(|e| format!("Failed to read directory {}: {}", source_dir.display(), e))?;
308	
309	    for entry in entries {
310	        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
311	        let path = entry.path();
312	
313	        if !path.is_file() {
314	            continue;
315	        }
316	
317	        let file_name = path
318	            .file_name()
319	            .and_then(|n| n.to_str())
320	            .unwrap_or("");
321	
322	        let matches = if is_command {
323	            zvofr_is_command_file(file_name, cipher)
324	        } else {
325	            zvofr_is_hook_file(file_name, cipher)
326	        };
327	
328	        if matches {
329	            let dest_path = dest_dir.join(file_name);
330	            fs::copy(&path, &dest_path)
331	                .map_err(|e| format!("Failed to copy {} to {}: {}", path.display(), dest_path.display(), e))?;
332	            count += 1;
333	        }
334	    }
335	
336	    Ok(count)
337	}
338	
339	/// Walk directory recursively, returning all file paths.
340	fn zvofr_walk_dir(dir: &Path) -> Result<Vec<PathBuf>, String> {
341	    let mut files = Vec::new();
342	
343	    if !dir.is_dir() {
344	        return Ok(files);
345	    }
346	
347	    let entries = fs::read_dir(dir)
348	        .map_err(|e| format!("Failed to read dir {}: {}", dir.display(), e))?;
349	
350	    for entry in entries {
351	        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
352	        let path = entry.path();
353	
354	        if path.is_dir() {
355	            files.extend(zvofr_walk_dir(&path)?);
356	        } else {
357	            files.push(path);
358	        }
359	    }
360	
361	    Ok(files)
362	}
363	
364	/// Check if path is within vov_veiled/ directory.
365	fn zvofr_is_veiled_path(rel_path: &Path) -> bool {
366	    for component in rel_path.components() {
367	        if let std::path::Component::Normal(name) = component {
368	            if name == "vov_veiled" {
369	                return true;
370	            }
371	        }
372	    }
373	    false
374	}
