376	/// Check if file is a command file (matches {cipher}c-*.md pattern).
377	fn zvofr_is_command_file(file_name: &str, cipher: &str) -> bool {
378	    let prefix = format!("{}{}", cipher, VOFC_COMMAND_SIGNET_SUFFIX);
379	    file_name.starts_with(&prefix) && file_name.ends_with(".md")
380	}
381	
382	/// Check if file is a hook file (matches {cipher}h-*.md pattern).
383	fn zvofr_is_hook_file(file_name: &str, cipher: &str) -> bool {
384	    let prefix = format!("{}{}", cipher, VOFC_HOOK_SIGNET_SUFFIX);
385	    file_name.starts_with(&prefix) && file_name.ends_with(".md")
386	}
