388	/// Compute order-independent super-SHA of staging directory.
389	fn zvofr_compute_super_sha(staging_dir: &Path) -> Result<String, String> {
390	    use std::collections::BTreeSet;
391	
392	    let mut file_hashes: BTreeSet<String> = BTreeSet::new();
393	
394	    let files = zvofr_walk_dir(staging_dir)?;
395	
396	    for file_path in files {
397	        let rel_path = file_path.strip_prefix(staging_dir)
398	            .map_err(|e| format!("Strip prefix failed: {}", e))?;
399	
400	        // Skip brand file itself
401	        if rel_path == Path::new("vvbf_brand.json") {
402	            continue;
403	        }
404	
405	        // Hash: path + content
406	        let path_str = rel_path.to_string_lossy();
407	        let content = fs::read(&file_path)
408	            .map_err(|e| format!("Failed to read {}: {}", file_path.display(), e))?;
409	
410	        let hash = zvofr_sha256_bytes(format!("{}:{}", path_str, zvofr_sha256_bytes(&content)).as_bytes());
411	        file_hashes.insert(hash);
412	    }
413	
414	    // Combine all hashes
415	    let combined = file_hashes.into_iter().collect::<Vec<_>>().join("\n");
416	    Ok(zvofr_sha256_bytes(combined.as_bytes()))
417	}
418	
419	/// Compute SHA256 of bytes, return hex string.
420	fn zvofr_sha256_bytes(data: &[u8]) -> String {
421	    // Simple SHA256 implementation using standard library
422	    // In production, would use sha2 crate, but avoiding extra dependencies
423	    use std::process::{Command, Stdio};
424	    use std::io::Write;
425	
426	    let mut child = Command::new("shasum")
427	        .args(["-a", "256"])
428	        .stdin(Stdio::piped())
429	        .stdout(Stdio::piped())
430	        .spawn()
431	        .expect("Failed to spawn shasum");
432	
433	    {
434	        let stdin = child.stdin.as_mut().expect("Failed to open stdin");
435	        stdin.write_all(data).expect("Failed to write to stdin");
436	    }
437	
438	    let output = child.wait_with_output().expect("Failed to read shasum output");
439	    let stdout = String::from_utf8_lossy(&output.stdout);
440	    stdout.split_whitespace().next().unwrap_or("").to_string()
441	}
