443	/// Load registry from JSON file.
444	fn zvofr_load_registry(path: &Path) -> Result<BTreeMap<u32, vofr_RegistryEntry>, String> {
445	    if !path.exists() {
446	        return Ok(BTreeMap::new());
447	    }
448	
449	    let content = fs::read_to_string(path)
450	        .map_err(|e| format!("Failed to read registry: {}", e))?;
451	
452	    let json: serde_json::Value = serde_json::from_str(&content)
453	        .map_err(|e| format!("Failed to parse registry JSON: {}", e))?;
454	
455	    let brands = json.get(VOFR_REGISTRY_BRANDS)
456	        .and_then(|v| v.as_object())
457	        .ok_or_else(|| "Registry missing 'vovr_brands' object".to_string())?;
458	
459	    let mut registry = BTreeMap::new();
460	
461	    for (key, value) in brands {
462	        let brand: u32 = key.parse()
463	            .map_err(|e| format!("Invalid brand key '{}': {}", key, e))?;
464	
465	        let date = value.get("date")
466	            .and_then(|v| v.as_str())
467	            .ok_or_else(|| format!("Brand {} missing 'date'", brand))?
468	            .to_string();
469	
470	        let sha = value.get("sha")
471	            .and_then(|v| v.as_str())
472	            .ok_or_else(|| format!("Brand {} missing 'sha'", brand))?
473	            .to_string();
474	
475	        registry.insert(brand, vofr_RegistryEntry { date, sha });
476	    }
477	
478	    Ok(registry)
479	}
480	
481	/// Save registry to JSON file.
482	fn zvofr_save_registry(path: &Path, registry: &BTreeMap<u32, vofr_RegistryEntry>) -> Result<(), String> {
483	    let mut brands = serde_json::Map::new();
484	
485	    for (brand, entry) in registry {
486	        let mut entry_obj = serde_json::Map::new();
487	        entry_obj.insert("date".to_string(), serde_json::Value::String(entry.date.clone()));
488	        entry_obj.insert("sha".to_string(), serde_json::Value::String(entry.sha.clone()));
489	        brands.insert(brand.to_string(), serde_json::Value::Object(entry_obj));
490	    }
491	
492	    let mut root = serde_json::Map::new();
493	    root.insert(VOFR_REGISTRY_BRANDS.to_string(), serde_json::Value::Object(brands));
494	
495	    let json = serde_json::to_string_pretty(&serde_json::Value::Object(root))
496	        .map_err(|e| format!("Failed to serialize registry: {}", e))?;
497	
498	    fs::write(path, json)
499	        .map_err(|e| format!("Failed to write registry: {}", e))?;
500	
501	    Ok(())
502	}
503	
504	/// Find brand by SHA.
505	fn zvofr_find_by_sha(registry: &BTreeMap<u32, vofr_RegistryEntry>, sha: &str) -> Option<u32> {
506	    for (brand, entry) in registry {
507	        if entry.sha == sha {
508	            return Some(*brand);
509	        }
510	    }
511	    None
512	}
513	
514	/// Allocate next sequential brand.
515	fn zvofr_allocate_brand(registry: &BTreeMap<u32, vofr_RegistryEntry>) -> u32 {
516	    registry.keys().max().map(|m| m + 1).unwrap_or(VOFR_BRAND_START)
517	}
518	
519	/// Generate date string in YYMMDD-HHMM format.
520	fn zvofr_generate_date() -> String {
521	    use std::process::Command;
522	
523	    let output = Command::new("date")
524	        .args(["+%y%m%d-%H%M"])
525	        .output()
526	        .expect("Failed to run date command");
527	
528	    String::from_utf8_lossy(&output.stdout).trim().to_string()
529	}
530	
531	/// Write brand file to staging.
532	fn zvofr_write_brand_file(
533	    path: &Path,
534	    brand: u32,
535	    date: &str,
536	    sha: &str,
537	    commit: &str,
538	    kits: &[String],
539	) -> Result<(), String> {
540	    let mut root = serde_json::Map::new();
541	
542	    root.insert(VOFR_BRAND_BRAND.to_string(), serde_json::Value::Number(brand.into()));
543	    root.insert(VOFR_BRAND_DATE.to_string(), serde_json::Value::String(date.to_string()));
544	    root.insert(VOFR_BRAND_SHA.to_string(), serde_json::Value::String(sha.to_string()));
545	    root.insert(VOFR_BRAND_COMMIT.to_string(), serde_json::Value::String(commit.to_string()));
546	
547	    let kit_values: Vec<serde_json::Value> = kits
548	        .iter()
549	        .map(|k| serde_json::Value::String(k.clone()))
550	        .collect();
551	    root.insert(VOFR_BRAND_KITS.to_string(), serde_json::Value::Array(kit_values));
552	
553	    let json = serde_json::to_string_pretty(&serde_json::Value::Object(root))
554	        .map_err(|e| format!("Failed to serialize brand file: {}", e))?;
555	
556	    fs::write(path, json)
557	        .map_err(|e| format!("Failed to write brand file: {}", e))?;
558	
559	    Ok(())
560	}
