562	#[cfg(test)]
563	mod tests {
564	    use super::*;
565	
566	    #[test]
567	    fn vofr_is_command_file_test() {
568	        assert!(zvofr_is_command_file("jjc-heat-mount.md", "jj"));
569	        assert!(zvofr_is_command_file("vvc-commit.md", "vv"));
570	        assert!(!zvofr_is_command_file("jju_utility.sh", "jj"));
571	        assert!(!zvofr_is_command_file("README.md", "jj"));
572	        assert!(!zvofr_is_command_file("jjc-heat-mount.txt", "jj"));
573	    }
574	
575	    #[test]
576	    fn vofr_is_veiled_path_test() {
577	        assert!(zvofr_is_veiled_path(Path::new("vov_veiled/test.rs")));
578	        assert!(zvofr_is_veiled_path(Path::new("foo/vov_veiled/bar.rs")));
579	        assert!(!zvofr_is_veiled_path(Path::new("commands/jjc-test.md")));
580	        assert!(!zvofr_is_veiled_path(Path::new("buc_command.sh")));
581	    }
582	
583	    #[test]
584	    fn vofr_brand_allocation_test() {
585	        let empty: BTreeMap<u32, vofr_RegistryEntry> = BTreeMap::new();
586	        assert_eq!(zvofr_allocate_brand(&empty), VOFR_BRAND_START);
587	
588	        let mut registry = BTreeMap::new();
589	        registry.insert(1000, vofr_RegistryEntry {
590	            date: "260117-1400".to_string(),
591	            sha: "abc123".to_string(),
592	        });
593	        assert_eq!(zvofr_allocate_brand(&registry), 1001);
594	
595	        registry.insert(1005, vofr_RegistryEntry {
596	            date: "260117-1500".to_string(),
597	            sha: "def456".to_string(),
598	        });
599	        assert_eq!(zvofr_allocate_brand(&registry), 1006);
600	    }
601	}
