455	/// Parse burc.env file to extract environment variables.
456	/// BURC_PROJECT_ROOT is the path from burc.env's location to the project root.
457	/// BURC_TOOLS_DIR is resolved relative to the resolved project_root (per BURC spec).
458	pub fn vofe_parse_burc(path: &Path) -> Result<vofe_BurcEnv, String> {
459	    if !path.exists() {
460	        return Err(format!("burc.env not found: {}", path.display()));
461	    }
462	
463	    // Get the parent directory of burc.env for path resolution
464	    let burc_parent = path
465	        .parent()
466	        .ok_or_else(|| "burc.env path has no parent directory".to_string())?;
467	
468	    let content = fs::read_to_string(path)
469	        .map_err(|e| format!("Failed to read burc.env: {}", e))?;
470	
471	    let mut vars: HashMap<String, String> = HashMap::new();
472	
473	    for line in content.lines() {
474	        let line = line.trim();
475	
476	        // Skip comments and empty lines
477	        if line.is_empty() || line.starts_with('#') {
478	            continue;
479	        }
480	
481	        // Parse KEY=VALUE (handle quoted values)
482	        if let Some(eq_pos) = line.find('=') {
483	            let key = line[..eq_pos].trim();
484	            let mut value = line[eq_pos + 1..].trim();
485	
486	            // Remove surrounding quotes if present
487	            if (value.starts_with('"') && value.ends_with('"'))
488	                || (value.starts_with('\'') && value.ends_with('\''))
489	            {
490	                value = &value[1..value.len() - 1];
491	            }
492	
493	            vars.insert(key.to_string(), value.to_string());
494	        }
495	    }
496	
497	    let tools_dir_str = vars
498	        .get("BURC_TOOLS_DIR")
499	        .ok_or_else(|| "burc.env missing required variable: BURC_TOOLS_DIR".to_string())?;
500	
501	    let project_root_str = vars
502	        .get("BURC_PROJECT_ROOT")
503	        .ok_or_else(|| "burc.env missing required variable: BURC_PROJECT_ROOT".to_string())?;
504	
505	    // BURC_PROJECT_ROOT is the path from burc.env's location to project root
506	    let project_root = burc_parent.join(project_root_str);
507	    let project_root = project_root
508	        .canonicalize()
509	        .map_err(|e| format!("BURC_PROJECT_ROOT path invalid ({}): {}", project_root.display(), e))?;
510	
511	    // Resolve tools_dir relative to project_root (per BURC spec)
512	    let tools_dir = project_root.join(tools_dir_str);
513	    let tools_dir = tools_dir
514	        .canonicalize()
515	        .map_err(|e| format!("BURC_TOOLS_DIR path invalid ({}): {}", tools_dir.display(), e))?;
516	
517	    // Parse BURC_MANAGED_KITS (comma-separated list)
518	    let managed_kits_str = vars
519	        .get("BURC_MANAGED_KITS")
520	        .ok_or_else(|| "burc.env missing required variable: BURC_MANAGED_KITS".to_string())?;
521	
522	    let managed_kits: Vec<String> = managed_kits_str
523	        .split(',')
524	        .map(|s| s.trim().to_string())
525	        .filter(|s| !s.is_empty())
526	        .collect();
527	
528	    if managed_kits.is_empty() {
529	        return Err("BURC_MANAGED_KITS must specify at least one kit".to_string());
530	    }
531	
532	    Ok(vofe_BurcEnv {
533	        tools_dir,
534	        project_root,
535	        managed_kits,
536	    })
537	}
