539	/// Read brand file and extract brand and kit list.
540	fn zvofe_read_brand(path: &Path) -> Result<(u32, Vec<String>), String> {
541	    if !path.exists() {
542	        return Err(format!("Brand file not found: {}", path.display()));
543	    }
544	
545	    let content = fs::read_to_string(path)
546	        .map_err(|e| format!("Failed to read brand file: {}", e))?;
547	
548	    let json: serde_json::Value = serde_json::from_str(&content)
549	        .map_err(|e| format!("Failed to parse brand JSON: {}", e))?;
550	
551	    let brand = json
552	        .get(VOFE_BRAND_BRAND)
553	        .and_then(|v| v.as_u64())
554	        .map(|v| v as u32)
555	        .ok_or_else(|| "Brand file missing brand".to_string())?;
556	
557	    let kits = json
558	        .get(VOFE_BRAND_KITS)
559	        .and_then(|v| v.as_array())
560	        .ok_or_else(|| "Brand file missing kits array".to_string())?;
561	
562	    let kit_ids: Vec<String> = kits
563	        .iter()
564	        .filter_map(|v| v.as_str().map(String::from))
565	        .collect();
566	
567	    if kit_ids.is_empty() {
568	        return Err("Brand file has empty kits array".to_string());
569	    }
570	
571	    Ok((brand, kit_ids))
572	}
