663	/// Check if file is a command file (matches {cipher}c-*.md pattern).
664	fn zvofe_is_command_file(file_name: &str, cipher: &str) -> bool {
665	    let prefix = format!("{}{}", cipher, VOFC_COMMAND_SIGNET_SUFFIX);
666	    file_name.starts_with(&prefix) && file_name.ends_with(".md")
667	}
