780	/// Build the `@`-include region body: one line per public guidance file of each
781	/// installed kit, in registry order, written project-root-relative.
782	fn zvofe_build_include_body(
783	    burc: &vofe_BurcEnv,
784	    kit_ids: &[String],
785	) -> Result<String, String> {
786	    let tools_rel = burc
787	        .tools_dir
788	        .strip_prefix(&burc.project_root)
789	        .map_err(|_| {
790	            format!(
791	                "BURC_TOOLS_DIR ({}) is not under project root ({})",
792	                burc.tools_dir.display(),
793	                burc.project_root.display()
794	            )
795	        })?;
796	
797	    let mut lines = Vec::new();
798	    for kit in DISTRIBUTABLE_KITS {
799	        let kit_id = kit.cipher.kit_id();
800	        if !kit_ids.iter().any(|k| k == &kit_id) {
801	            continue;
802	        }
803	        for include in kit.claude_includes {
804	            let rel = tools_rel.join(&kit_id).join(include);
805	            lines.push(format!("@{}", rel.display()));
806	        }
807	    }
808	
809	    Ok(lines.join("\n"))
810	}
