834	/// Remove files matching a pattern from a directory.
835	/// If is_command is true, matches {cipher}c-*.md; otherwise matches {cipher}h_*
836	/// Returns count of files removed.
837	fn zvofe_remove_matching_files(dir: &Path, cipher: &str, is_command: bool) -> Result<u32, String> {
838	    let mut count = 0u32;
839	
840	    let entries = fs::read_dir(dir)
841	        .map_err(|e| format!("Failed to read directory {}: {}", dir.display(), e))?;
842	
843	    for entry in entries {
844	        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
845	        let path = entry.path();
846	
847	        if !path.is_file() {
848	            continue;
849	        }
850	
851	        let file_name = path
852	            .file_name()
853	            .and_then(|n| n.to_str())
854	            .unwrap_or("");
855	
856	        let matches = if is_command {
857	            zvofe_is_command_file(file_name, cipher)
858	        } else {
859	            zvofe_is_hook_file(file_name, cipher)
860	        };
861	
862	        if matches {
863	            fs::remove_file(&path)
864	                .map_err(|e| format!("Failed to remove {}: {}", path.display(), e))?;
865	            count += 1;
866	        }
867	    }
868	
869	    Ok(count)
870	}
