172	/// Single CLAUDE.md managed-region tag for the consolidated @-include block.
173	///
174	/// The target repo's CLAUDE.md carries exactly one
175	/// `<!-- MANAGED:{tag}:BEGIN -->` / `:END` region whose body is the set of
176	/// `@`-include lines for installed kits' public guidance files. The guidance
177	/// content lives in the `@`-targets, never inline — so the region cannot go
178	/// stale. Replaces the former per-kit inline-template mechanism.
179	pub const VOFC_INCLUDE_REGION_TAG: &str = "VVK-INCLUDES";
