261	/// Check if a prefix is registered.
262	pub fn vofc_is_registered(prefix: &str) -> bool {
263	    vofc_find_by_prefix(prefix).is_some()
264	}
265	
266	/// Validate terminal exclusivity: ensure no prefix is a prefix of another.
267	/// Returns None if valid, or Some pair of conflicting ciphers.
268	pub fn vofc_validate_terminal_exclusivity() -> Option<(&'static vofc_Cipher, &'static vofc_Cipher)> {
269	    for (i, a) in ALL_CIPHERS.iter().enumerate() {
270	        for b in ALL_CIPHERS.iter().skip(i + 1) {
271	            if a.prefix.starts_with(b.prefix) || b.prefix.starts_with(a.prefix) {
272	                return Some((a, b));
273	            }
274	        }
275	    }
276	    None
277	}
