109	/// Convert handler (exit_code, output) to MCP CallToolResult.
110	fn jjrm_result(result: (i32, String)) -> Result<CallToolResult, McpError> {
111	    let (code, output) = result;
112	    if code == 0 {
113	        Ok(CallToolResult::success(vec![Content::text(output)]))
114	    } else {
115	        Ok(CallToolResult::error(vec![Content::text(output)]))
116	    }
117	}
