126	// Dispatch lifecycle — jjsodp_command_lifecycle (Operation Taxonomy in JJS0)
127	// ============================================================================
128	
129	/// Shared dispatch body: lock → load → call handler → persist → return output.
130	///
131	/// Per jjdk_sole_operator, every operation locks and persists unconditionally.
132	/// The handler returns output text on success — it has no knowledge of locks,
133	/// persistence, or commit messages.
134	fn zjjrm_dispatch_inner(
135	    cmd: &str,
136	    firemark: &crate::jjrf_favor::jjrf_Firemark,
137	    size_limit: u64,
138	    handler: impl FnOnce(&mut crate::jjrg_gallops::jjrg_Gallops) -> Result<String, String>,
139	) -> Result<CallToolResult, McpError> {
140	    use vvc::vvco_Output;
141	
142	    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
143	        Ok(l) => l,
144	        Err(e) => {
145	            return Ok(CallToolResult::error(vec![Content::text(
146	                format!("jjx {}: error: {}", cmd, e),
147	            )]));
148	        }
149	    };
